SELECT CODE, DTL_CODE, RTRIM(DTL_CODE_NM) DTL_CODE_NM, DATE_FORMAT(START_DATE, '%Y-%m-%d') START_DATE , DATE_FORMAT(END_DATE, '%Y-%m-%d') END_DATE , USE_YN, IFNull(SORT,'-') SORT FROM T_COMM_MST_DTL WHERE CODE = #{code}
AND ( DTL_CODE LIKE CONCAT('%',#{dtl_code},'%') )
ORDER BY CODE ,DTL_CODE


SELECT 'Y'
  FROM T_COMM_MST_DTL
 WHERE CODE      = #{code}
   AND DTL_CODE  = #{dtl_code}
